class Twitter:
    def __init__(self):
        self.t = collections.defaultdict(list); self.f = collections.defaultdict(set); self.time = 0
    def postTweet(self, userId, tweetId):
        self.t[userId].append((self.time, tweetId)); self.time -= 1
    def getNewsFeed(self, userId):
        h = []; self.f[userId].add(userId)
        for u in self.f[userId]:
            for x in self.t[u][-10:]:
                heapq.heappush(h, x)
        return [x for t, x in heapq.nsmallest(10, h)]
    def follow(self, f1, f2): self.f[f1].add(f2)
    def unfollow(self, f1, f2): self.f[f1].discard(f2)

